import React from 'react'
import styled from 'styled-components'


const DepartmentTitle = styled.span `
font-size:0.8rem;
`

const Check = styled.input `
text-align:center;
`


export default function Checkbox ({value, children}) {
	return (
		<>
			<label><Check type='checkbox'value={value}/><DepartmentTitle>{children}</DepartmentTitle></label>
		</>

	)
}
